def extract_token_from_metadata(metadata):
    """Extract bearer token from gRPC metadata."""
    for key, value in metadata:
        if key == "authorization":
            if value.startswith("Bearer "):
                return value[7:]
            return value
    return None


class AuthenticationInterceptor(ServerInterceptor):
    """
    gRPC server interceptor that enforces authentication on RPCs.
    
    - Health/metrics endpoints: No auth required (safe public endpoints)
    - Admin endpoints: Requires ADMIN-level authentication (stricter)
    - All other endpoints: Requires standard user authentication
    """

    def __init__(self):
        self._request_counts = defaultdict(int)

    def _is_unauthenticated_method(self, method: str) -> bool:
        """Check if the method is in the allow-list for unauthenticated access."""
        return method in UNAUTHENTICATED_METHODS

    def _is_admin_method(self, method: str) -> bool:
        """Check if the method requires admin-level authentication."""
        return method.startswith(ADMIN_METHOD_PREFIX)

    def _abort_unauthenticated(self, context, message="Authentication required"):
        """Abort the RPC with UNAUTHENTICATED status."""
        context.abort(grpc.StatusCode.UNAUTHENTICATED, message)

    def _abort_permission_denied(self, context, message="Permission denied"):
        """Abort the RPC with PERMISSION_DENIED status."""
        context.abort(grpc.StatusCode.PERMISSION_DENIED, message)

    def intercept_service(self, continuation, handler_call_details):
        """Main interception point for all incoming RPCs."""
        method = handler_call_details.method
        metadata = dict(handler_call_details.invocation_metadata or [])

        self._request_counts[method] += 1
        logger.info(f"Intercepted RPC: {method}")

        # 1. Allow unauthenticated access to health/metrics endpoints
        if self._is_unauthenticated_method(method):
            logger.info(f"Allowing unauthenticated access to public endpoint: {method}")
            return continuation(handler_call_details)

        # 2. Extract token - required for all other endpoints
        token = None
        authorization = metadata.get("authorization", "")
        if authorization.startswith("Bearer "):
            token = authorization[7:]
        elif authorization:
            token = authorization

        if not token:
            logger.warning(f"No auth token provided for {method}")
            # Return a handler that will abort with UNAUTHENTICATED
            return self._create_abort_handler(
                grpc.StatusCode.UNAUTHENTICATED,
                "Authentication required: no token provided"
            )

