def generate_user_token(user_id: str, expiry_hours: int = 24) -> str:
    """Generate a user JWT token."""
    payload = {
        "sub": user_id,
        "role": "user",
        "iat": time.time(),
        "exp": time.time() + (expiry_hours * 3600),
    }
    return jwt.encode(payload, SECRET_KEY, algorithm="HS256")


def generate_admin_token(admin_id: str, expiry_hours: int = 1) -> str:
    """
    Generate an admin JWT token.
    Note: Admin tokens have shorter expiry by default for security.
    """
    payload = {
        "sub": admin_id,
        "role": "admin",
        "iat": time.time(),
        "exp": time.time() + (expiry_hours * 3600),
    }
    return jwt.encode(payload, ADMIN_SECRET_KEY, algorithm="HS256")


