    server.start()
    logger.info(f"gRPC server started on port {port}")
    logger.info("Authentication policy:")
    logger.info(f"  Unauthenticated (public): {UNAUTHENTICATED_METHODS}")
    logger.info(f"  Admin (requires admin token): {ADMIN_METHOD_PREFIX}*")
